sql:
SELECT AVG(level) FROM character_attributes
WHERE character_id IN (
  SELECT character_id FROM character_statistics
  WHERE statistic_id = (
    SELECT statistic_id FROM statistics WHERE statistic_name = 'Health'
  )
  AND value > (
    SELECT AVG(value) FROM character_statistics WHERE statistic_id = (
      SELECT statistic_id FROM statistics WHERE statistic_name = 'Health'
    )
  )
);

SELECT identifier, game_index
FROM characters
WHERE character_id > 5;

SELECT flavor_id, COUNT(*) AS flavor_statistic_count
FROM flavor_statistics
GROUP BY flavor_id;

SELECT SUM(effect_value) AS total_increase_value
FROM character_flavor_statistics
WHERE statistic_id = 1 AND effect_type = 'increase';

SELECT MAX(effect_value) 
FROM character_flavor_statistics 
WHERE character_id = 1;

